(t, fc) => {
  // Necker cube ambiguous wireframe
  background(20); stroke(0, 255, 200); strokeWeight(1); noFill();
  let angle = t * 0.6;
  let sz = W(25, {wave:'valleys', t:t*0.3, range:[7, 12], seed:14, frequency:0.5});
